ath\", {\n    d: \"M464 256a208 208 0 1 0-416 0 208 208 0 1 0 416 0M0 256a256 256 0 1 1 512 0 256 256 0 1 1-512 0m188.3-108.9c7.6-4.2 16.8-4.1 24.3.5l144 88c7.1 4.4 11.5 12.1 11.5 20.5s-4.4 16.1-11.5 20.5l-144 88c-7.4 4.5-16.7 4.7-24.3.5S176 352.9 176 344.2V168c0-8.7 4.7-16.7 12.3-20.9\"\n  })));\n};\nexport { SvgCirclePlay as ReactComponent };\nexport default \"data:image/svg+xml;base64,\";","function _extends() { return _extends = Object.assign ? Object.assign.bind() : function (n) { for (var e = 1; e < arguments.length; e++) { var t = arguments[e]; for (var r in t) ({}).hasOwnProperty.call(t, r) && (n[r] = t[r]); } return n; }, _extends.apply(null, arguments); }\nimport * as React from \"react\";\nvar SvgCircleStop = function SvgCircleStop(props) {\n  return /*#__PURE__*/React.createElement(\"svg\", _extends({\n    xmlns: \"http://www.w3.org/2000/svg\",\n    width: 100,\n    height: 100,\n    viewBox: \"0 0 75 75\"\n  }, props), /*#__PURE__*/React.createElement(\"path\", {\n    d: \"M0 0h75v75H0z\",\n    style: {\n      fill: \"#fff\",\n      fillOpacity: 1,\n      stroke: \"none\"\n    }\n  }), /*#__PURE__*/React.createElement(\"path\", {\n    d: \"M0 0h75v75H0z\",\n    style: {\n      fill: \"#fff\",\n      fillOpacity: 1,\n      stroke: \"none\"\n    }\n  }), /*#__PURE__*/React.createElement(\"path\", {\n    d: \"M37.5 0C16.79 0 0 16.79 0 37.5S16.79 75 37.5 75 75 58.21 75 37.5 58.21 0 37.5 0m0 69.23c-17.492 0-31.73-14.234-31.73-31.73S20.008 5.77 37.5 5.77c17.496 0 31.73 14.234 31.73 31.73S54.996 69.23 37.5 69.23m0 0\",\n    style: {\n      stroke: \"none\",\n      fillRule: \"nonzero\",\n      fill: \"#000\",\n      fillOpacity: 1\n    }\n  }), /*#__PURE__*/React.createElement(\"path\", {\n    d: \"M23.078 23.078h28.844v28.844H23.078Zm0 0\",\n    style: {\n      stroke: \"none\",\n      fillRule: \"nonzero\",\n      fill: \"#000\",\n      fillOpacity: 1\n    }\n  }));\n};\nexport { SvgCircleStop as ReactComponent };\nexport default \"data:image/svg+xml;base64,\";","import { createElement, Fragment } from \"@wordpress/element\";\r\nimport { __ } from \"@wordpress/i18n\";\r\n\r\nimport {\r\n  TextControl,\r\n  PanelRow,\r\n  RadioControl,\r\n  ComboboxControl,\r\n  __experimentalUnitControl as UnitControl,\r\n} from \"@wordpress/components\";\r\n\r\nimport { PanelColorSettings } from \"@wordpress/block-editor\";\r\n\r\nconst helpLink = createElement(\r\n  \"a\",\r\n  { href: \"https://fontawesome.com/search\", target: \"_blank\" },\r\n  \"FontAwesome\",\r\n);\r\n\r\nconst helpTextCode = createElement(\r\n  \"span\",\r\n  {},\r\n  helpLink,\r\n  __(\r\n    \"Select the icon from and enter Unicode (the upper right four digits of the selection dialog). \",\r\n    \"block-collections\",\r\n  ),\r\n);\r\n\r\nconst helpImageURL = createElement(\r\n  \"span\",\r\n  {},\r\n  __(\"Enter the URL for the image.\", \"block-collections\"),\r\n);\r\n\r\nconst helpTextFamily = createElement(\r\n  \"span\",\r\n  {},\r\n  __(\r\n    \"Please select the first class name shown in the HTML code field of the selection dialog. \",\r\n    \"block-collections\",\r\n  ),\r\n);\r\n\r\nconst units = [\r\n  { value: \"px\", label: \"px\" },\r\n  { value: \"em\", label: \"em\" },\r\n  { value: \"rem\", label: \"rem\" },\r\n];\r\n\r\nconst family_option = [\r\n  { value: \"Font Awesome 6 Free\", label: \"SOLID\" },\r\n  { value: \"Font Awesome 6 Brands\", label: \"BRANDS\" },\r\n];\r\n\r\n// 1. アイコンスタイルの型定義\r\ninterface IconStyle {\r\n  icon_type: \"awesome\" | \"image\" | \"avatar\" | string;\r\n  icon_url?: string;\r\n  icon_name?: string;\r\n  icon_pos?: \"left\" | \"right\" | string;\r\n  icon_size?: string;\r\n  icon_color?: string;\r\n  icon_space?: string;\r\n  icon_family?: string;\r\n}\r\n\r\n// 2. Props の型定義\r\ninterface IconControlProps {\r\n  iconStyle: IconStyle;\r\n  setPosition?: boolean; // 配置設定を表示するかどうかのフラグ\r\n  onChange: (newStyle: IconStyle) => void;\r\n}\r\n\r\nexport default ({ iconStyle, setPosition, onChange }: IconControlProps) => {\r\n  const {\r\n    icon_type,\r\n    icon_url,\r\n    icon_name,\r\n    icon_pos,\r\n    icon_size,\r\n    icon_color,\r\n    icon_space,\r\n    icon_family,\r\n  } = iconStyle;\r\n\r\n  return (\r\n    <>\r\n      <label className=\"components-base-control__label\">\r\n        {__(\"Icon Types\", \"block-collections\")}\r\n      </label>\r\n      <PanelRow className=\"itmar_position_row\">\r\n        <RadioControl\r\n          selected={icon_type}\r\n          options={[\r\n            { label: __(\"Awesome\", \"block-collections\"), value: \"awesome\" },\r\n            { label: __(\"Image\", \"block-collections\"), value: \"image\" },\r\n            { label: __(\"Avatar\", \"block-collections\"), value: \"avatar\" },\r\n          ]}\r\n          onChange={(newValue) => {\r\n            const newStyle = { ...iconStyle, icon_type: newValue };\r\n            onChange(newStyle);\r\n          }}\r\n        />\r\n      </PanelRow>\r\n      {icon_type === \"awesome\" && (\r\n        <>\r\n          <TextControl\r\n            label={__(\"icon name\", \"block-collections\")}\r\n            help={typeof helpTextCode !== \"undefined\" ? helpTextCode : \"\"}\r\n            value={icon_name || \"\"}\r\n            onChange={(newValue) => {\r\n              onChange({ ...iconStyle, icon_name: newValue });\r\n            }}\r\n          />\r\n\r\n          <ComboboxControl\r\n            label={__(\"Icon Family\", \"block-collections\")}\r\n            help={typeof helpTextFamily !== \"undefined\" ? helpTextFamily : \"\"}\r\n            options={typeof family_option !== \"undefined\" ? family_option : []}\r\n            value={icon_family ? icon_family : \"Font Awesome 6 Free\"}\r\n            onChange={(newValue) => {\r\n              onChange({ ...iconStyle, icon_family: newValue || \"\" });\r\n            }}\r\n          />\r\n        </>\r\n      )}\r\n      {icon_type === \"image\" && (\r\n        <TextControl\r\n          label={__(\"icon url\", \"block-collections\")}\r\n          help={typeof helpImageURL !== \"undefined\" ? helpImageURL : \"\"}\r\n          value={icon_url || \"\"}\r\n          onChange={(newValue) => {\r\n            onChange({ ...iconStyle, icon_url: newValue });\r\n          }}\r\n        />\r\n      )}\r\n      <PanelRow className=\"sizing_row\">\r\n        <UnitControl\r\n          dragDirection=\"e\"\r\n          onChange={(newValue) => {\r\n            const newStyle = { ...iconStyle, icon_size: newValue };\r\n            onChange(newStyle);\r\n          }}\r\n          label={__(\"Size\", \"block-collections\")}\r\n          value={icon_size}\r\n          units={units}\r\n        />\r\n        {setPosition && (\r\n          <UnitControl\r\n            dragDirection=\"e\"\r\n            onChange={(newValue) => {\r\n              const newStyle = { ...iconStyle, icon_space: newValue };\r\n              onChange(newStyle);\r\n            }}\r\n            label={__(\"spacing to end\", \"block-collections\")}\r\n            value={icon_space}\r\n            units={units}\r\n          />\r\n        )}\r\n      </PanelRow>\r\n\r\n      <PanelColorSettings\r\n        title={__(\"Color settings\", \"itmar_location\")}\r\n        colorSettings={[\r\n          {\r\n            value: icon_color || \"\",\r\n            onChange: (newValue) => {\r\n              onChange({ ...iconStyle, icon_color: newValue || \"\" });\r\n            },\r\n            label: __(\"Icon color\", \"itmar_location\"),\r\n          },\r\n        ]}\r\n      />\r\n      {setPosition && (\r\n        <>\r\n          <label className=\"components-base-control__label\">\r\n            {__(\"Arrangement\", \"block-collections\")}\r\n          </label>\r\n          <PanelRow className=\"itmar_position_row\">\r\n            <RadioControl\r\n              selected={icon_pos}\r\n              options={[\r\n                { label: __(\"left\", \"block-collections\"), value: \"left\" },\r\n                { label: __(\"right\", \"block-collections\"), value: \"right\" },\r\n              ]}\r\n              onChange={(newValue) => {\r\n                const newStyle = { ...iconStyle, icon_pos: newValue };\r\n                onChange(newStyle);\r\n              }}\r\n            />\r\n          </PanelRow>\r\n        </>\r\n      )}\r\n    </>\r\n  );\r\n};\r\n","import { createElement, Fragment } from \"@wordpress/element\";\r\nimport { __ } from \"@wordpress/i18n\";\r\nimport { PanelColorSettings } from \"@wordpress/block-editor\";\r\nimport {\r\n  PanelBody,\r\n  PanelRow,\r\n  ToggleControl,\r\n  RangeControl,\r\n  RadioControl,\r\n} from \"@wordpress/components\";\r\nimport { useState, useEffect } from \"@wordpress/element\";\r\nimport { dispatch } from \"@wordpress/data\";\r\nimport { hslToRgb16, HexToRGB, rgb16ToHsl } from \"./hslToRgb\";\r\n\r\n//方向と距離\r\n// 1. 方向の型定義（リテラル型で制限）\r\ntype CornerDirection =\r\n  | \"top_left\"\r\n  | \"top_right\"\r\n  | \"bottom_left\"\r\n  | \"bottom_right\"\r\n  | \"right_bottom\"\r\n  | \"top\";\r\n\r\n// 2. 戻り値のインターフェース\r\ninterface DirectionDigits {\r\n  topLeft: number;\r\n  topRight: number;\r\n  bottomLeft: number;\r\n  bottomRight: number;\r\n}\r\n\r\n/**\r\n * 方向と距離に基づいて、各頂点の数値を算出する\r\n */\r\nconst dirctionDigit = (\r\n  direction: CornerDirection,\r\n  distance: number,\r\n): DirectionDigits => {\r\n  // 初期値（デフォルト）を設定しておくことで、switch 漏れを防ぐ\r\n  let destTopLeft = 0;\r\n  let destTopRight = 0;\r\n  let destBottomLeft = 0;\r\n  let destBottomRight = 0;\r\n  switch (direction) {\r\n    case \"top_left\":\r\n      destTopLeft = distance;\r\n      destTopRight = distance;\r\n      destBottomLeft = distance * -1;\r\n      destBottomRight = distance * -1;\r\n      break;\r\n    case \"top_right\":\r\n      destTopLeft = distance * -1;\r\n      destTopRight = distance;\r\n      destBottomLeft = distance;\r\n      destBottomRight = distance * -1;\r\n      break;\r\n    case \"bottom_left\":\r\n      destTopLeft = distance;\r\n      destTopRight = distance * -1;\r\n      destBottomLeft = distance * -1;\r\n      destBottomRight = distance;\r\n      break;\r\n    case \"bottom_right\":\r\n      destTopLeft = distance * -1;\r\n      destTopRight = distance * -1;\r\n      destBottomLeft = distance;\r\n      destBottomRight = distance;\r\n      break;\r\n    case \"right_bottom\":\r\n      destTopLeft = distance;\r\n      destTopRight = distance * -1;\r\n      destBottomLeft = distance * -1;\r\n      destBottomRight = distance;\r\n      break;\r\n    case \"top\":\r\n      destTopLeft = 0;\r\n      destTopRight = 0;\r\n      destBottomLeft = distance * -1;\r\n      destBottomRight = distance;\r\n      break;\r\n  }\r\n  return {\r\n    topLeft: destTopLeft,\r\n    topRight: destTopRight,\r\n    bottomLeft: destBottomLeft,\r\n    bottomRight: destBottomRight,\r\n  };\r\n};\r\n\r\n// グラデーションの色値は通常'linear-gradient'または'radial-gradient'で始まるので、\r\n// これらのキーワードを探すことでグラデーションかどうかを判断します。\r\nfunction isGradient(\r\n  colorValue: string | undefined | null,\r\n): colorValue is string {\r\n  // 1. 値が存在しない、または文字列でない場合は false\r\n  if (typeof colorValue !== \"string\") {\r\n    return false;\r\n  }\r\n  return (\r\n    colorValue.includes(\"linear-gradient\") ||\r\n    colorValue.includes(\"radial-gradient\")\r\n  );\r\n}\r\n\r\n// 1. ShadowState の型定義\r\nexport interface ShadowState {\r\n  shadowType: \"nomal\" | \"newmor\" | \"claymor\" | \"glassmor\";\r\n  spread: number;\r\n  lateral: number;\r\n  longitude: number;\r\n  nomalBlur: number;\r\n  shadowColor: string;\r\n  blur: number;\r\n  intensity: number;\r\n  distance: number;\r\n  newDirection: CornerDirection; // 以前定義した型\r\n  clayDirection: CornerDirection;\r\n  embos: \"swell\" | \"dent\";\r\n  opacity: number;\r\n  depth: number;\r\n  bdBlur: number;\r\n  expand: number;\r\n  glassblur: number;\r\n  glassopa: number;\r\n  hasOutline: boolean;\r\n  baseColor: string;\r\n}\r\n\r\n// 戻り値の型（Reactのstyle属性を持つオブジェクト）\r\ninterface ShadowResult {\r\n  style: React.CSSProperties;\r\n}\r\n\r\nexport const ShadowElm = (shadowState: ShadowState): ShadowResult | null => {\r\n  //let baseColor;\r\n  const {\r\n    shadowType,\r\n    spread,\r\n    lateral,\r\n    longitude,\r\n    nomalBlur,\r\n    shadowColor,\r\n    blur,\r\n    intensity,\r\n    distance,\r\n    newDirection,\r\n    clayDirection,\r\n    embos,\r\n    opacity,\r\n    depth,\r\n    bdBlur,\r\n    expand,\r\n    glassblur,\r\n    glassopa,\r\n    hasOutline,\r\n    baseColor,\r\n  } = shadowState;\r\n\r\n  //ノーマル\r\n  if (shadowType === \"nomal\") {\r\n    //boxshadowの生成\r\n    const ShadowStyle =\r\n      embos === \"dent\"\r\n        ? {\r\n            style: {\r\n              boxShadow: `${lateral}px ${longitude}px ${nomalBlur}px ${spread}px transparent, inset ${lateral}px ${longitude}px ${nomalBlur}px ${spread}px ${shadowColor}`,\r\n            },\r\n          }\r\n        : {\r\n            style: {\r\n              boxShadow: `${lateral}px ${longitude}px ${nomalBlur}px ${spread}px ${shadowColor}, inset ${lateral}px ${longitude}px ${nomalBlur}px ${spread}px transparent`,\r\n            },\r\n          };\r\n    //Shadowのスタイルを返す\r\n    return ShadowStyle;\r\n  }\r\n  //ニューモフィズム\r\n  // --- ニューモフィズム ---\r\n  else if (shadowType === \"newmor\") {\r\n    if (isGradient(baseColor)) {\r\n      (dispatch(\"core/notices\") as any).createNotice(\r\n        \"error\",\r\n        __(\r\n          \"Neumorphism cannot be set when the background color is a gradient.\",\r\n          \"itmar_guest_contact_block\",\r\n        ),\r\n        { type: \"snackbar\", isDismissible: true },\r\n      );\r\n      return null;\r\n    }\r\n\r\n    const hslValue = rgb16ToHsl(baseColor);\r\n    if (!hslValue) return null; // カラー変換失敗時のガード\r\n\r\n    const lightVal = Math.min(hslValue.lightness + intensity, 100);\r\n    const darkVal = Math.max(hslValue.lightness - intensity, 0);\r\n\r\n    const lightValue = hslToRgb16(hslValue.hue, hslValue.saturation, lightVal);\r\n    const darkValue = hslToRgb16(hslValue.hue, hslValue.saturation, darkVal);\r\n    const dircObj = dirctionDigit(newDirection, distance);\r\n\r\n    const baseBoxShadow =\r\n      embos === \"swell\"\r\n        ? `${dircObj.topLeft}px ${dircObj.topRight}px ${blur}px ${darkValue}, ${dircObj.bottomLeft}px ${dircObj.bottomRight}px ${blur}px ${lightValue}, inset ${dircObj.topLeft}px ${dircObj.topRight}px ${blur}px transparent, inset ${dircObj.bottomLeft}px ${dircObj.bottomRight}px ${blur}px transparent`\r\n        : `${dircObj.topLeft}px ${dircObj.topRight}px ${blur}px transparent, ${dircObj.bottomLeft}px ${dircObj.bottomRight}px ${blur}px transparent, inset ${dircObj.topLeft}px ${dircObj.topRight}px ${blur}px ${darkValue}, inset ${dircObj.bottomLeft}px ${dircObj.bottomRight}px ${blur}px ${lightValue}`;\r\n\r\n    return {\r\n      style: {\r\n        border: \"none\",\r\n        background: baseColor,\r\n        boxShadow: baseBoxShadow,\r\n      },\r\n    };\r\n  }\r\n\r\n  // --- クレイモーフィズム ---\r\n  else if (shadowType === \"claymor\") {\r\n    if (isGradient(baseColor)) {\r\n      (dispatch(\"core/notices\") as any).createNotice(\r\n        \"error\",\r\n        __(\r\n          \"claymorphism cannot be set when the background color is a gradient.\",\r\n          \"itmar_guest_contact_block\",\r\n        ),\r\n        { type: \"snackbar\", isDismissible: true },\r\n      );\r\n      return null;\r\n    }\r\n    const rgbValue = HexToRGB(baseColor);\r\n    if (!rgbValue) return null;\r\n\r\n    const outsetObj = dirctionDigit(clayDirection, expand);\r\n    const insetObj = dirctionDigit(clayDirection, depth);\r\n\r\n    return {\r\n      style: {\r\n        background: `rgba(255, 255, 255, ${opacity})`,\r\n        backdropFilter: `blur(${bdBlur}px)`,\r\n        border: \"none\",\r\n        boxShadow: `${outsetObj.topLeft}px ${outsetObj.bottomRight}px ${expand * 2}px 0px rgba(${rgbValue.red}, ${rgbValue.green}, ${rgbValue.blue}, 0.5), inset ${insetObj.topRight}px ${insetObj.bottomLeft}px 16px 0px rgba(${rgbValue.red}, ${rgbValue.green}, ${rgbValue.blue}, 0.6), inset 0px 11px 28px 0px rgb(255, 255, 255)`,\r\n      },\r\n    };\r\n  }\r\n\r\n  // --- グラスモーフィズム ---\r\n  else if (shadowType === \"glassmor\") {\r\n    const glassBoxShadow =\r\n      embos === \"swell\"\r\n        ? `0 8px 12px 0 rgba( 31, 38, 135, 0.37 ), inset 0 8px 12px 0 transparent`\r\n        : `0 8px 12px 0 transparent, inset 0 8px 12px 0 rgba( 31, 38, 135, 0.37 )`;\r\n\r\n    return {\r\n      style: {\r\n        backgroundColor: `rgba(255, 255, 255, ${glassopa})`,\r\n        ...(hasOutline ? { border: `1px solid rgba(255, 255, 255, 0.4)` } : {}),\r\n        borderRightColor: `rgba(255, 255, 255, 0.2)`,\r\n        borderBottomColor: `rgba(255, 255, 255, 0.2)`,\r\n        backdropFilter: `blur(${glassblur}px)`,\r\n        boxShadow: glassBoxShadow,\r\n      },\r\n    };\r\n  }\r\n\r\n  return null;\r\n};\r\n\r\ninterface ShadowStyleProps {\r\n  shadowStyle: ShadowState;\r\n  onChange: (elm: ShadowResult, state: ShadowState) => void;\r\n}\r\nconst ShadowStyle = ({ shadowStyle, onChange }: ShadowStyleProps) => {\r\n  const [shadowState, setShadowState] = useState<ShadowState>(shadowStyle);\r\n\r\n  const {\r\n    shadowType,\r\n    spread,\r\n    lateral,\r\n    longitude,\r\n    nomalBlur,\r\n    shadowColor,\r\n    blur,\r\n    intensity,\r\n    distance,\r\n    newDirection,\r\n    clayDirection,\r\n    embos,\r\n    opacity,\r\n    depth,\r\n    bdBlur,\r\n    expand,\r\n    glassblur,\r\n    glassopa,\r\n    hasOutline,\r\n  } = shadowState;\r\n\r\n  //シャドーのスタイル変更と背景色変更に伴う親コンポーネントの変更\r\n  useEffect(() => {\r\n    const shadowElm = ShadowElm(shadowState);\r\n    if (shadowElm) onChange(shadowElm, shadowState);\r\n  }, [shadowState]);\r\n\r\n  // ヘルパー: ステートの一部を更新\r\n  const updateState = (partial: Partial<ShadowState>) => {\r\n    setShadowState((prev) => ({ ...prev, ...partial }));\r\n  };\r\n\r\n  return (\r\n    <>\r\n      <PanelBody\r\n        title={__(\"Shadow Type\", \"block-collections\")}\r\n        initialOpen={true}\r\n      >\r\n        <div className=\"itmar_shadow_type\">\r\n          <RadioControl\r\n            selected={shadowType}\r\n            options={[\r\n              { label: __(\"Normal\", \"block-collections\"), value: \"nomal\" },\r\n              {\r\n                label: __(\"Neumorphism\", \"block-collections\"),\r\n                value: \"newmor\",\r\n              },\r\n              {\r\n                label: __(\"Claymorphism\", \"block-collections\"),\r\n                value: \"claymor\",\r\n              },\r\n              {\r\n                label: __(\"Glassmorphism\", \"block-collections\"),\r\n                value: \"glassmor\",\r\n              },\r\n            ]}\r\n            onChange={(val) =>\r\n              updateState({ shadowType: val as ShadowState[\"shadowType\"] })\r\n            }\r\n          />\r\n        </div>\r\n        {shadowType !== \"claymor\" && (\r\n          <div className=\"embos\">\r\n            <RadioControl\r\n              label={__(\"unevenness\", \"block-collections\")}\r\n              selected={embos}\r\n              options={[\r\n                { label: \"Swell\", value: \"swell\" },\r\n                { label: \"Dent\", value: \"dent\" },\r\n              ]}\r\n              onChange={(val) =>\r\n                updateState({ embos: val as ShadowState[\"embos\"] })\r\n              }\r\n            />\r\n          </div>\r\n        )}\r\n      </PanelBody>\r\n\r\n      {/* --- Normal Settings --- */}\r\n      {shadowType === \"nomal\" && (\r\n        <PanelBody\r\n          title={__(\"Normal settings\", \"block-collections\")}\r\n          initialOpen={false}\r\n        >\r\n          <RangeControl\r\n            value={spread}\r\n            label={__(\"Spread\", \"block-collections\")}\r\n            max={50}\r\n            min={0}\r\n            onChange={(val) => updateState({ spread: val ?? 0 })}\r\n          />\r\n          <RangeControl\r\n            value={lateral}\r\n            label={__(\"Lateral direction\", \"block-collections\")}\r\n            max={50}\r\n            min={0}\r\n            onChange={(val) => updateState({ lateral: val ?? 0 })}\r\n          />\r\n          <RangeControl\r\n            value={longitude}\r\n            label={__(\"Longitudinal direction\", \"block-collections\")}\r\n            max={50}\r\n            min={0}\r\n            onChange={(val) => updateState({ longitude: val ?? 0 })}\r\n          />\r\n          <RangeControl\r\n            value={nomalBlur}\r\n            label={__(\"Blur\", \"block-collections\")}\r\n            max={20}\r\n            min={0}\r\n            onChange={(val) => updateState({ nomalBlur: val ?? 0 })}\r\n          />\r\n          <PanelColorSettings\r\n            title={__(\"Shadow Color Setting\", \"block-collections\")}\r\n            colorSettings={[\r\n              {\r\n                value: shadowColor,\r\n                label: __(\"Choose Shadow color\", \"block-collections\"),\r\n                onChange: (val) => updateState({ shadowColor: val || \"\" }),\r\n              },\r\n            ]}\r\n          />\r\n        </PanelBody>\r\n      )}\r\n\r\n      {/* --- Neumorphism Settings --- */}\r\n      {shadowType === \"newmor\" && (\r\n        <PanelBody\r\n          title={__(\"Neumorphism settings\", \"block-collections\")}\r\n          initialOpen={false}\r\n        >\r\n          <RangeControl\r\n            value={distance}\r\n            label={__(\"Distance\", \"block-collections\")}\r\n            max={50}\r\n            min={0}\r\n            onChange={(val) => updateState({ distance: val ?? 0 })}\r\n          />\r\n          <RangeControl\r\n            value={intensity}\r\n            label={__(\"Intensity\", \"block-collections\")}\r\n            max={100}\r\n            min={0}\r\n            onChange={(val) => updateState({ intensity: val ?? 0 })}\r\n          />\r\n          <RangeControl\r\n            value={blur}\r\n            label={__(\"Blur\", \"block-collections\")}\r\n            max={20}\r\n            min={0}\r\n            onChange={(val) => updateState({ blur: val ?? 0 })}\r\n          />\r\n          <PanelRow>\r\n            <div className=\"light_direction\">\r\n              <RadioControl\r\n                selected={newDirection}\r\n                options={[\r\n                  { label: \"Top Left\", value: \"top_left\" },\r\n                  { label: \"Top Right\", value: \"top_right\" },\r\n                  { label: \"Bottom Left\", value: \"bottom_left\" },\r\n                  { label: \"Bottom Right\", value: \"bottom_right\" },\r\n                ]}\r\n                onChange={(val) =>\r\n                  updateState({ newDirection: val as CornerDirection })\r\n                }\r\n              />\r\n            </div>\r\n          </PanelRow>\r\n        </PanelBody>\r\n      )}\r\n\r\n      {/* --- Claymorphism Settings --- */}\r\n      {shadowType === \"claymor\" && (\r\n        <PanelBody\r\n          title={__(\"Claymorphism settings\", \"block-collections\")}\r\n          initialOpen={false}\r\n        >\r\n          <RangeControl\r\n            value={opacity}\r\n            label={__(\"Opacity\", \"block-collections\")}\r\n            max={1}\r\n            min={0}\r\n            step={0.1}\r\n            onChange={(val) => updateState({ opacity: val ?? 1 })}\r\n          />\r\n          <RangeControl\r\n            value={depth}\r\n            label=\"Depth\"\r\n            max={20}\r\n            min={0}\r\n            onChange={(val) => updateState({ depth: val ?? 0 })}\r\n          />\r\n          <RangeControl\r\n            value={expand}\r\n            label=\"Expand\"\r\n            max={50}\r\n            min={0}\r\n            onChange={(val) => updateState({ expand: val ?? 0 })}\r\n          />\r\n          <RangeControl\r\n            value={bdBlur}\r\n            label=\"Background Blur\"\r\n            max={10}\r\n            min={0}\r\n            onChange={(val) => updateState({ bdBlur: val ?? 0 })}\r\n          />\r\n          <div className=\"light_direction claymor\">\r\n            <RadioControl\r\n              selected={clayDirection}\r\n              options={[\r\n                { label: \"Right Bottom\", value: \"right_bottom\" },\r\n                { label: \"Top Right\", value: \"top_right\" },\r\n                { label: \"Top\", value: \"top\" },\r\n              ]}\r\n              onChange={(val) =>\r\n                updateState({ clayDirection: val as CornerDirection })\r\n              }\r\n            />\r\n          </div>\r\n        </PanelBody>\r\n      )}\r\n\r\n      {/* --- Glassmorphism Settings --- */}\r\n      {shadowType === \"glassmor\" && (\r\n        <PanelBody\r\n          title={__(\"Grassmophism settings\", \"block-collections\")}\r\n          initialOpen={false}\r\n        >\r\n          <RangeControl\r\n            value={glassblur}\r\n            label={__(\"Glass blur\", \"block-collections\")}\r\n            max={20}\r\n            min={0}\r\n            onChange={(val) => updateState({ glassblur: val ?? 0 })}\r\n          />\r\n          <RangeControl\r\n            value={glassopa}\r\n            label={__(\"Glass Opacity\", \"block-collections\")}\r\n            max={1}\r\n            min={0}\r\n            step={0.1}\r\n            onChange={(val) => updateState({ glassopa: val ?? 0.5 })}\r\n          />\r\n          <ToggleControl\r\n            label={__(\"Show outline\", \"block-collections\")}\r\n            checked={hasOutline}\r\n            onChange={(val) => updateState({ hasOutline: val })}\r\n          />\r\n        </PanelBody>\r\n      )}\r\n    </>\r\n  );\r\n};\r\nexport default ShadowStyle;\r\n","import { createElement, Fragment } from \"@wordpress/element\";\r\nimport {\r\n  PanelBody,\r\n  PanelRow,\r\n  RadioControl,\r\n  ToggleControl,\r\n  __experimentalUnitControl as UnitControl,\r\n} from \"@wordpress/components\";\r\n\r\nimport Select from \"react-select\";\r\nimport { __ } from \"@wordpress/i18n\";\r\n\r\n// 1. FontStyle の型定義\r\ninterface FontStyle {\r\n  default_fontSize: string;\r\n  mobile_fontSize: string;\r\n  fontSize?: string; // 互換性のため\r\n  fontFamily: string;\r\n  fontWeight: string;\r\n  isItalic: boolean;\r\n}\r\n\r\n// 2. Props の型定義\r\ninterface TypographyControlsProps {\r\n  title: string;\r\n  fontStyle: FontStyle;\r\n  initialOpen?: boolean;\r\n  isMobile: boolean;\r\n  onChange: (newStyle: FontStyle) => void;\r\n}\r\n\r\nconst TypographyControls = ({\r\n  title,\r\n  fontStyle,\r\n  initialOpen = true,\r\n  isMobile,\r\n  onChange,\r\n}: TypographyControlsProps) => {\r\n  const {\r\n    default_fontSize,\r\n    mobile_fontSize,\r\n    fontFamily,\r\n    fontWeight,\r\n    isItalic,\r\n  } = fontStyle;\r\n\r\n  const fontFamilyOptions = [\r\n    {\r\n      value: \"Arial, sans-serif\",\r\n      label: \"Arial\",\r\n      fontFamily: \"Arial, sans-serif\",\r\n    },\r\n    {\r\n      value: \"Courier New, monospace\",\r\n      label: \"Courier New\",\r\n      fontFamily: \"Courier New, monospace\",\r\n    },\r\n    { value: \"Georgia, serif\", label: \"Georgia\", fontFamily: \"Georgia, serif\" },\r\n    {\r\n      label: \"Noto Sans JP\",\r\n      value: \"Noto Sans JP, sans-serif\",\r\n      fontFamily: \"Noto Sans JP, sans-serif\",\r\n    },\r\n    {\r\n      label: \"Texturina\",\r\n      value: \"Texturina, serif\",\r\n      fontFamily: \"Texturina, serif\",\r\n    },\r\n  ];\r\n\r\n  const units = [\r\n    { value: \"px\", label: \"px\" },\r\n    { value: \"em\", label: \"em\" },\r\n    { value: \"rem\", label: \"rem\" },\r\n  ];\r\n\r\n  // react-select 用のスタイル定義\r\n  const customStyles = {\r\n    option: (provided: any, state: any) => ({\r\n      ...provided,\r\n      fontFamily: state.data.fontFamily,\r\n    }),\r\n  };\r\n\r\n  // 内部コンポーネント FontSelect\r\n  const FontSelect = ({\r\n    label,\r\n    value,\r\n    onSelectChange,\r\n  }: {\r\n    label: string;\r\n    value: string;\r\n    onSelectChange: (val: string) => void;\r\n  }) => (\r\n    <>\r\n      {label && (\r\n        <label className=\"components-base-control__label\">{label}</label>\r\n      )}\r\n      <Select\r\n        options={fontFamilyOptions}\r\n        value={fontFamilyOptions.find((option) => option.value === value)}\r\n        onChange={(newValue: any) => {\r\n          onSelectChange(newValue.value);\r\n        }}\r\n        styles={customStyles}\r\n      />\r\n    </>\r\n  );\r\n\r\n  return (\r\n    <PanelBody title={title} initialOpen={initialOpen}>\r\n      <UnitControl\r\n        label={\r\n          !isMobile\r\n            ? __(\"Size(desktop)\", \"block-collections\")\r\n            : __(\"Size(mobile)\", \"block-collections\")\r\n        }\r\n        value={!isMobile ? default_fontSize : mobile_fontSize}\r\n        units={units}\r\n        onChange={(newValue?: string) => {\r\n          const safeValue =\r\n            newValue !== undefined && newValue !== \"\" ? newValue : \"0px\";\r\n          const set_size = !isMobile\r\n            ? { default_fontSize: safeValue }\r\n            : { mobile_fontSize: safeValue };\r\n          onChange({ ...fontStyle, ...set_size });\r\n        }}\r\n      />\r\n\r\n      <FontSelect\r\n        label={__(\"font family\", \"block-collections\")}\r\n        value={fontFamily}\r\n        onSelectChange={(newValue) => {\r\n          onChange({ ...fontStyle, fontFamily: newValue });\r\n        }}\r\n      />\r\n\r\n      <label className=\"components-base-control__label\">\r\n        {__(\"font weight\", \"block-collections\")}\r\n      </label>\r\n      <PanelRow className=\"itmar_weight_row\">\r\n        <RadioControl\r\n          selected={fontWeight}\r\n          options={[\r\n            { label: \"LIGHT\", value: \"300\" },\r\n            { label: \"REGULAR\", value: \"400\" },\r\n            { label: \"MEDIUM\", value: \"500\" },\r\n            { label: \"S-BOLD\", value: \"600\" },\r\n            { label: \"BOLD\", value: \"700\" },\r\n            { label: \"BLACK\", value: \"900\" },\r\n          ]}\r\n          onChange={(newValue) => {\r\n            const newStyle = { ...fontStyle, fontWeight: newValue };\r\n            onChange(newStyle);\r\n          }}\r\n        />\r\n      </PanelRow>\r\n\r\n      <ToggleControl\r\n        label={__(\"Italic display\", \"block-collections\")}\r\n        checked={isItalic}\r\n        onChange={(newValue: boolean) => {\r\n          onChange({ ...fontStyle, isItalic: newValue });\r\n        }}\r\n      />\r\n    </PanelBody>\r\n  );\r\n};\r\nexport default TypographyControls;\r\n","import { CSSProperties } from \"react\";\r\n\r\n// sideの最初の文字を大文字にする関数\r\nconst capitalizeFirstLetter = (string: string) => {\r\n  return string.charAt(0).toUpperCase() + string.slice(1);\r\n};\r\n// objectかどうか判定する関数\r\nconst isObject = (value: unknown): value is Record<string, any> => {\r\n  return value !== null && typeof value === \"object\" && !Array.isArray(value);\r\n};\r\n\r\n//角丸のパラメータを返す\r\n// 1. 角丸オブジェクトの型を定義\r\ninterface RadiusObject {\r\n  value?: string;\r\n  topLeft?: string;\r\n  topRight?: string;\r\n  bottomLeft?: string;\r\n  bottomRight?: string;\r\n}\r\nexport const radius_prm = (radius: RadiusObject | undefined): string => {\r\n  // radius が存在しない場合は空文字を返す\r\n  if (!radius) return \"\";\r\n\r\n  const ret_radius_prm =\r\n    Object.keys(radius).length === 1 && radius.value\r\n      ? radius.value\r\n      : `${radius.topLeft || \"\"} ${radius.topRight || \"\"} ${radius.bottomRight || \"\"} ${radius.bottomLeft || \"\"}`;\r\n\r\n  return ret_radius_prm.trim(); // 余計な空白を削除して返す\r\n};\r\n//スペースのパラメータを返す\r\n// 1. 余白オブジェクトの型を定義\r\ninterface SpaceObject {\r\n  top?: string | number;\r\n  right?: string | number;\r\n  bottom?: string | number;\r\n  left?: string | number;\r\n}\r\nexport const space_prm = (space: SpaceObject | undefined): string => {\r\n  // spaceが存在しない、または空の場合は空文字を返す\r\n  if (!space) return \"\";\r\n\r\n  // 各値が undefined の場合に備えてデフォルト値（\"0